// ─── Componente de botão de pagamento ────────────────────────────────────────

function PaymentCard({ onClick, disabled, loading, brand, description, children }) {
  const brands = {
    stripe: {
      accent: "#635BFF",
      bg: "#F5F4FF",
      border: "#DDD9FF",
      hoverBorder: "#635BFF",
    },
    mp: {
      accent: "#009EE3",
      bg: "#F0FAFF",
      border: "#C2E8F8",
      hoverBorder: "#009EE3",
    },
  };

  const style = brands[brand];

  return (
    <button
      onClick={onClick}
      disabled={disabled}
      style={{
        display: "flex",
        alignItems: "center",
        justifyContent: "space-between",
        gap: 16,
        width: "100%",
        padding: "20px 24px",
        background: disabled ? "#F5F5F5" : "#FFFFFF",
        border: `1.5px solid ${style.border}`,
        borderRadius: 6,
        cursor: disabled ? "not-allowed" : "pointer",
        opacity: disabled ? 0.55 : 1,
        transition: "border-color 0.2s, box-shadow 0.2s, transform 0.15s",
        textAlign: "left",
        fontFamily: "'DM Sans', sans-serif",
      }}
      onMouseEnter={(e) => {
        if (!disabled) {
          e.currentTarget.style.borderColor = style.hoverBorder;
          e.currentTarget.style.boxShadow = `0 4px 20px ${style.accent}22`;
          e.currentTarget.style.transform = "translateY(-1px)";
        }
      }}
      onMouseLeave={(e) => {
        e.currentTarget.style.borderColor = style.border;
        e.currentTarget.style.boxShadow = "none";
        e.currentTarget.style.transform = "translateY(0)";
      }}
    >
      {/* Logo */}
      <div style={{
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        width: 48,
        height: 48,
        borderRadius: 10,
        background: style.bg,
        flexShrink: 0,
      }}>
        {children}
      </div>

      {/* Texto */}
      <div style={{ flex: 1 }}>
        <div style={{
          fontSize: 14,
          fontWeight: 500,
          color: "#111",
          marginBottom: 2,
          letterSpacing: "0.01em",
        }}>
          {loading ? "Processando..." : `Pagar com ${brand === "stripe" ? "Stripe" : "Mercado Pago"}`}
        </div>
        <div style={{ fontSize: 12, color: "#999", fontWeight: 300 }}>
          {description}
        </div>
      </div>

      {/* Seta */}
      {!loading && (
        <svg width="16" height="16" viewBox="0 0 16 16" fill="none" style={{ flexShrink: 0 }}>
          <path d="M3 8h10M9 4l4 4-4 4" stroke={style.accent} strokeWidth="1.6"
            strokeLinecap="round" strokeLinejoin="round" />
        </svg>
      )}

      {loading && (
        <svg width="18" height="18" viewBox="0 0 18 18" fill="none"
          style={{ flexShrink: 0, animation: "ck-spin 0.8s linear infinite" }}>
          <circle cx="9" cy="9" r="7" stroke={style.accent} strokeWidth="2" strokeOpacity="0.25" />
          <path d="M9 2a7 7 0 017 7" stroke={style.accent} strokeWidth="2" strokeLinecap="round" />
        </svg>
      )}
    </button>
  );
}

// ─── Página principal ─────────────────────────────────────────────────────────

export default function Payments() {
  const { state } = useLocation();
  const cartItems =
    state?.items || JSON.parse(localStorage.getItem("checkoutItems") || "[]");

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const subtotal = cartItems.reduce(
    (sum, item) => sum + (item.price || 0) * (item.quantity || 0), 0
  );

  const formatItems = () =>
    cartItems.map((item) => {
      const productId = item._id || item.productId || item.id || item.product?._id;
      if (!productId) throw new Error("Produto inválido no carrinho.");
      const quantity = Number(item.quantity || item.qty || 1);
      if (!quantity || quantity < 1) throw new Error("Quantidade inválida.");
      return { productId, quantity };
    });

  const checkout = async (url, label) => {
    setLoading(true);
    setError(null);
    try {
      const token = localStorage.getItem("token");
      if (!token) throw new Error("Você precisa estar logado");

      const res = await fetch(url, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${token}`,
        },
        body: JSON.stringify({ items: formatItems() }),
      });

      const data = await res.json();
      if (!res.ok || !data?.url) throw new Error(data?.error || `Erro no ${label}`);

      toast.success(`Redirecionando para ${label}...`);
      setTimeout(() => { window.location.href = data.url; }, 600);
    } catch (err) {
      console.error(err);
      setError(err.message);
      toast.error(err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:wght@300;400&family=DM+Sans:wght@300;400;500&display=swap');
        @keyframes ck-spin { to { transform: rotate(360deg); } }
      `}</style>

      <div className="payment-container">
        <div className="payment-grid">

          {/* ── LEFT ── */}
          <div className="payment-left">
            <h1 className="payment-title" style={{ fontFamily: "'Cormorant Garamond', serif", fontWeight: 300 }}>
              Pagamento
            </h1>

            <p style={{
              fontFamily: "'DM Sans', sans-serif",
              fontSize: 13,
              color: "#888",
              fontWeight: 300,
              marginBottom: 20,
              marginTop: -8,
            }}>
              Escolha a forma de pagamento:
            </p>

            <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
              <PaymentCard
                brand="stripe"
                description="Cartão de crédito, débito ou Link"
                onClick={() => checkout(STRIPE_URL, "Stripe")}
                disabled={loading || cartItems.length === 0}
                loading={loading}
              >
                <StripeLogo />
              </PaymentCard>

              <PaymentCard
                brand="mp"
                description="Pix, boleto ou cartão"
                onClick={() => checkout(MP_URL, "Mercado Pago")}
                disabled={loading || cartItems.length === 0}
                loading={loading}
              >
                <MercadoPagoLogo />
              </PaymentCard>
            </div>

            {error && (
              <p className="payment-error" style={{
                marginTop: 14,
                fontSize: 13,
                color: "#D94040",
                fontFamily: "'DM Sans', sans-serif",
              }}>
                {error}
              </p>
            )}

            {/* Selos de segurança */}
            <div style={{
              display: "flex",
              alignItems: "center",
              gap: 6,
              marginTop: 20,
              color: "#BBB",
              fontSize: 11,
              fontFamily: "'DM Sans', sans-serif",
              fontWeight: 300,
            }}>
              <svg width="13" height="13" viewBox="0 0 14 14" fill="none">
                <path d="M7 1L1.5 3.5v4C1.5 10.5 4 12.8 7 13.5c3-0.7 5.5-3 5.5-6V3.5L7 1z"
                  stroke="#BBB" strokeWidth="1.2" strokeLinejoin="round" />
                <path d="M4.5 7l2 2 3-3" stroke="#BBB" strokeWidth="1.2"
                  strokeLinecap="round" strokeLinejoin="round" />
              </svg>
              Pagamento 100% seguro e criptografado
            </div>
          </div>

          {/* ── RIGHT ── */}
          <div className="payment-right">
            <h2 className="summary-title" style={{ fontFamily: "'DM Sans', sans-serif" }}>
              Resumo
            </h2>

            <div className="summary-items">
              {cartItems.map((item, index) => (
                <div className="summary-item" key={index}>
                  <span>{item.image && <img src={item.image} alt={item.name} className="summary-image" />}</span>
                  <span>{item.name}</span>
                  <span>{formatPrice(item.price)} x {item.quantity}</span>
                  <span>{formatPrice((item.price || 0) * (item.quantity || 0))}</span>
                </div>
              ))}
            </div>

            <div className="summary-total">
              <span>Total</span>
              <span>{formatPrice(subtotal)}</span>
            </div>
          </div>

        </div>
      </div>
    </>
  );
}